Bash(node -e "
import { createClient } from ''@supabase/supabase-js'';
const supabase = createClient\(
  ''https://phwgirodvaptywzyibmi.supabase.co'',
  ''eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6InBod2dpcm9kdmFwdHl3enlpYm1pIiwicm9sZSI6ImFub24iLCJpYXQiOjE3Njc2NTc4MjYsImV4cCI6MjA4MzIzMzgyNn0.X89cVFVB0fQnfmZdD48M-mghrA08kjNQPSOegXDtS3Y''
\);

// is_hit_winがNULLで、かつ結果があるレースがあるか確認
const { data: nullWithResults, error } = await supabase
  .from\(''predictions''\)
  .select\(''race_id, model_id, top_pick''\)
  .is\(''is_hit_win'', null\)
  .limit\(100\);

if \(error\) {
  console.error\(''Error:'', error.message\);
  process.exit\(1\);
}

// それぞれのrace_idに結果があるかチェック
let hasResultCount = 0;
let noResultCount = 0;

for \(const pred of nullWithResults\) {
  const { data: result } = await supabase
    .from\(''race_results''\)
    .select\(''race_id''\)
    .eq\(''race_id'', pred.race_id\)
    .single\(\);

  if \(result\) {
    hasResultCount++;
  } else {
    noResultCount++;
  }
}

console.log\(''is_hit_win=NULLの予測（サンプル100件）:''\);
console.log\(''  結果あり:'', hasResultCount\);
console.log\(''  結果なし:'', noResultCount\);

if \(hasResultCount > 0\) {
  console.log\(''\\n⚠️ 結果があるのにis_hit_winがNULLの予測がある → バックフィルが必要''\);
} else {
  console.log\(''\\n✅ is_hit_win=NULLは全て結果なしのレース → 正常''\);
}
")
